def pareto_front(sequences #Dataframe containing a sequence and its two scores
                ):
    """
    Keep only Pareto-optimal sequences:
    no other sequence has both scores >= and at least one strictly greater.
    Args:
        sequences (DataFrame): A dataframe of sequences and their two scores.
        
    Returns:
        pareto: the list of rows corresponding to pareto optima (no sequence with both scores higher).
    """
    pareto = []
    for s in sequences:
        dominated = False
        for t in sequences:
            if (t["Score_TRSp"] >= s["Score_TRSp"] and
                t["Score_TRSpAvd"] >= s["Score_TRSpAvd"] and
                (t["Score_TRSp"] > s["Score_TRSp"] or
                 t["Score_TRSpAvd"] > s["Score_TRSpAvd"])):
                dominated = True
                break
        if not dominated:
            pareto.append(s)
    return pareto

def codons_compatible_with_AA(target_aa):
    """
    Return all codons X such that replacing any 'A' in X by {A,C,G,T}
    can yield a codon encoding target_aa.
    """
    compatible = []

    for codon, aa in genetic_code.items():
        if aa != target_aa:
            continue

        # For this "real" codon, generate all abstract codons
        # where any non-A position must match, and A can stand for anything
        abstract = []
        for nt in codon:
            if nt == "A":
                abstract.append(["A"])  # must stay A in abstract
            else:
                abstract.append([nt, "A"])  # could have been wildcard A

        for triplet in product(*abstract):
            compatible.append("".join(triplet))

    return set(compatible)

def mutate_adenine(codon):
    """Generate all possible codons by mutating adenine (A) to T, C, or G."""
    mutations = []
    for i, base in enumerate(codon):
        if base == 'A':
            for new_base in ['T', 'C', 'G']:
                mutated_codon = codon[:i] + new_base + codon[i+1:]
                mutations.append(mutated_codon)
    return mutations

def get_aa_by_adenine_mutation(codon):
    """Return the list of unique amino acids reachable by adenine mutation in the codon."""
    mutations = mutate_adenine(codon)
    unique_aa = set()

    for mutated_codon in mutations:
        aa = genetic_code.get(mutated_codon, None)
        if aa is not None:
            unique_aa.add(aa)

    return sorted(unique_aa)



def valid_seq_reach_AAs(
    seq,
    dict_allowed=None,
    dict_allowed_max_min=None,
    frame_offset=0,
    freq_min=0.2,
    codon_usage=codon_usage_ecoli
):
    """Checks whether a DNA sequence can reach a set of target amino acids through adenine mutagenesis
    at each codon position."""
    # No constraints → original sequence only
    if not dict_allowed:
        return [seq]

    # Store allowed codons per position
    allowed_codons_per_pos = {}

    for i, allowed_aas in dict_allowed.items():
        # Start with codons compatible with first AA
        candidate_codons = set(
            codons_compatible_with_AA(allowed_aas[0])
        )

        # Intersect with other allowed AAs
        for aa in allowed_aas[1:]:
            candidate_codons &= set(
                codons_compatible_with_AA(aa)
            )

        # Apply codon usage filter
        filtered_codons = []
        for codon in candidate_codons:
            aa = genetic_code.get(codon)
            if aa not in codon_usage:
                continue
            if codon_usage[aa].get(codon, 0) > freq_min:
                filtered_codons.append(codon)
        # Check for codon that maximizes or minimizes diversity at that position, as indicated by dict_allowed_max_min
        if dict_allowed_max_min!=None and i in dict_allowed_max_min:
            if dict_allowed_max_min[i]=='max':
                L=[]
                for codon in filtered_codons: 
                    L.append(len(get_aa_by_adenine_mutation(codon)))
                filtered_codons=[filtered_codons[k] for k in range(len(L)) if L[k]==max(L)]
            elif dict_allowed_max_min[i]=='min':
                L=[]
                for codon in filtered_codons: 
                    L.append(len(get_aa_by_adenine_mutation(codon)))
                filtered_codons=[filtered_codons[k] for k in range(len(L)) if L[k]==min(L)]
        # If no valid codons → no valid sequences at all
        if not filtered_codons:
            print("No valid sequence!")
            return []

        allowed_codons_per_pos[i] = filtered_codons

    # Generate all combinations of codons across positions
    positions = sorted(allowed_codons_per_pos.keys())
    codon_combinations = product(
        *[allowed_codons_per_pos[i] for i in positions]
    )

    variants = []

    for combo in codon_combinations:
        new_seq = list(seq)
        for i, codon in zip(positions, combo):
            start = frame_offset + i * 3
            new_seq[start:start + 3] = codon
        variants.append("".join(new_seq))

    return variants

        
    
def propose_single_codon_changes(
    seq,
    dict_allowed=None,
    dict_allowed_max_min=None,
    frame_offset=0,
    freq_min=0.2,
    forbidden_positions=[],
    codon_usage=codon_usage_ecoli,
):
    """
    dict_allowed[i] = list of allowed TARGET amino acids at codon i
    """
    variants = []

    for i in range(frame_offset, len(seq) - 2, 3):
        if any(pos in forbidden_positions for pos in (i, i+1, i+2)):
            continue

        codon = seq[i:i+3]
        if dict_allowed!=None and (i-frame_offset)//3 in dict_allowed:
            allowed_aas = dict_allowed.get((i-frame_offset)//3, [])
        else:
            allowed_aas=None

        # No restriction → behave as before
        if allowed_aas==None:
            aa = genetic_code.get(codon)
            if aa not in codon_usage:
                continue

            ranked = sorted(
                codon_usage[aa].items(),
                key=lambda x: x[1],
                reverse=True,
            )

            for new_codon, usage in ranked:
                if usage <= freq_min or new_codon == codon:
                    continue
                variants.append(seq[:i] + new_codon + seq[i+3:])

        # Restricted case: AA → compatible codons
        else:
            
            candidate_codons = set(codons_compatible_with_AA(allowed_aas[0]))
            for aa in allowed_aas[1:]:
                candidate_codons &= codons_compatible_with_AA(aa)
            candidate_codons_not_stop=candidate_codons - codons_reaching_stop #remove codons reaching stop codons by A mutagenesis
            if not candidate_codons_not_stop:
                print('All valid codons reach stop codons')
            else:
                candidate_codons=candidate_codons_not_stop
            filter_codons=[]
            for new_codon in candidate_codons:
                aa = genetic_code.get(new_codon)
                
                if aa not in codon_usage:
                    continue

                usage = codon_usage[aa].get(new_codon, 0)
                if usage <= freq_min:
                    continue

                if new_codon == codon:
                    continue
                filter_codons.append(new_codon)
            candidate_codons=filter_codons
            if dict_allowed_max_min!=None and (i-frame_offset)//3 in dict_allowed_max_min:
                j=(i-frame_offset)//3
                if dict_allowed_max_min[j]=='max':
                    L=[]
                    for codon in candidate_codons: 
                        L.append(len(get_aa_by_adenine_mutation(codon)))
                    candidate_codons=[candidate_codons[k] for k in range(len(L)) if L[k]==max(L)]
                    
                elif dict_allowed_max_min[j]=='min':
                    L=[]
                    for codon in candidate_codons: 
                        L.append(len(get_aa_by_adenine_mutation(codon)))
                    candidate_codons=[candidate_codons[k] for k in range(len(L)) if L[k]==min(L)]

            for new_codon in candidate_codons:
                variants.append(seq[:i] + new_codon + seq[i+3:])

    return variants

def evaluate_sequences(variants):
    """
    Encode sequences, run classifiers, return list of dicts with scores.
    """
    seqs = [v for v in variants]
    Scores=score_list(seqs, #A list of strings of TRs DNA sequences
seqs, #A list of strings of TRs names
features=2)
    Score_TRSp = list(Scores['TR_Score_Sp'])
    Score_TRSpAvd = list(Scores['TR_Score_Avd'])
    plt.figure(figsize=(6,6))
    plt.scatter(Score_TRSp, Score_TRSpAvd, alpha=0.7)
    plt.xlabel("Score_TRSp")
    plt.ylabel("Score_TRSpAvd")
    plt.grid(True)
    plt.show()
    results = []
    for i, seq,  in enumerate(variants):
        results.append({
            "sequence": seq,
            "Score_TRSp": Score_TRSp[i],
            "Score_TRSpAvd": Score_TRSpAvd[i],
            "Score_geo_mean": np.sqrt(Score_TRSp[i] * Score_TRSpAvd[i])
        })
    return results

def check_any_AAC_position(dict_allowed,dict_allowed_max_min,length):
    if dict_allowed_max_min==None:
        return []
    else:
        forbidden_to_add=[]
        for i in range(length):
            if (i in dict_allowed_max_min) and (dict_allowed_max_min[i]=="max") and (not i in dict_allowed):
                forbidden_to_add.append(i)
        return(forbidden_to_add)

# %% ../nbs/API/05_predictions.ipynb #7c1cc23f-b21b-41a2-b03f-627eec8b5428
def optimize_sequence(
    original_seq,
    frame_offset= 0,
    dict_allowed_AAs = None,
    dict_allowed_AAs_max_min=None,
    CHANGES = 6,
    freq_min = 0.2,
    N = 1,
    forbidden_positions = [],
    threshold = 0.7,
    codon_usage = codon_usage_ecoli
):
    """
    Optimize a DNA sequence via synonymous codon substitutions.

    This function performs a beam-search–based optimization of a nucleotide
    sequence by iteratively proposing single-codon synonymous changes and
    evaluating them with the two scoring functions. The search stops early if a
    variant meets the specified score thresholds, otherwise the best Pareto-
    optimal solution is returned.

    Parameters
    ----------
    original_seq : str
        Original DNA sequence to optimize.
    frame_offset : int, default=0
        Reading-frame offset (0, 1, or 2) used when grouping codons.
    dict_allowed_AAs : dict, default=None
        Dictionary of positions (keys) and AAs (values) where you want to reach all AAs in the list with the codon. If not mentioned, does as before.
        Selects for codons which do not reach (by adenine mutation) stop codons. If not possible, allow them anyway.
    dict_allowed_AAs_max_min : dict, default=None
        Dictionary of positions (keys) and either you want maximum diversity ('max') or mimimum diversity ('min')  at the positions mentionned in dict_allowed_AAs. Diversity = number of AAs reachable by adenine mutations (already removed codons reaching stop codons). 
        If not mentioned, any sequence that fullfills dict_allowed_AAs[i] is accepted.
        If there is no list of accessible AAs for dict_allowed_AAs[i] but dict_allowed_AAs_min_max[i]=='max', it puts an AAC here and forbids the algorithm to change it.
    CHANGES : int, default=6
        Maximum number of codon substitutions allowed (on top of the AAs requirements from the previous argument).
    freq_min : float, default=0.2
        Lowest usage frequency acceptable.
    N : int, default=1
        Number of putative TR to output.
    forbidden_positions : list[int], optional
        Nucleotide positions that must not be modified.
    threshold : float, default=0.7
        Minimum required value for both `Score_TRSp` and `Score_TRSpAvd` to
        accept a sequence as optimal.
    codon_usage : dict, optional
        Codon usage table of E. Coli mapping amino acids to codons and frequencies.

    Returns
    -------
    dict
        Dictionary containing:
        - `Original_Sequence` : str  
          Input DNA sequence.
        - `New_Variant` : str  
          Optimized DNA sequence.
        - `Rank` : int or None  
          rank of the sequence (by score).
        - `Score` : float or None  
          score of the selected variant (geometrical mean).
        - `Score_TRSp` : float or None  
          TR+Sp score of the selected variant.
        - `Score_TRSpAvd` : float or None  
          Avd+TR+Sp score of the selected variant.

    Notes
    -----
    - The algorithm keeps only Pareto-optimal candidates at each iteration.
    - If no variant satisfies the threshold criteria, the best-scoring
      sequence after `CHANGES` iterations is returned.
    - Internal scoring and plotting are handled by `evaluate_sequences`.

    Examples
    --------
    ```python
    result = optimize_sequence("ATGGCTGCTTAA")
    result["New_Variant"]
    ```
    """
    codon_changes_done = 0
    if dict_allowed_AAs_max_min==None:
        beam = [original_seq]
        seq=original_seq
        forbidden_final=forbidden_positions
    elif check_any_AAC_position(dict_allowed_AAs,dict_allowed_AAs_max_min,len(original_seq)//3)!=[]: #Add AAC at positions where you want to maximize diversity but didn't precise the allowed AAs
        forbidden_to_add=check_any_AAC_position(dict_allowed_AAs,dict_allowed_AAs_max_min,len(original_seq)//3)
        seq=original_seq
        print(forbidden_to_add)
        print(seq)
        for i in forbidden_to_add:
            if seq[3*i+frame_offset:3*i+3+frame_offset]!="AAC":
                codon_changes_done += 1
            seq=seq[:3*i+frame_offset]+'AAC'+seq[3*i+3+frame_offset:]
            print(seq)
        print(seq)
        forbidden_to_add=[3*i+frame_offset for i in forbidden_to_add]
        
        beam = valid_seq_reach_AAs(
                seq,
                dict_allowed=dict_allowed_AAs,
                dict_allowed_max_min=dict_allowed_AAs_max_min,
                frame_offset=frame_offset,
                freq_min=freq_min,
                codon_usage=codon_usage
            )
        forbidden_final=forbidden_positions+forbidden_to_add
    else:
        forbidden_to_add=[]
        beam = valid_seq_reach_AAs(
                original_seq,
                dict_allowed=dict_allowed_AAs,
                dict_allowed_max_min=dict_allowed_AAs_max_min,
                frame_offset=frame_offset,
                freq_min=freq_min,
                codon_usage=codon_usage
            )
        seq=original_seq
        forbidden_final=forbidden_positions
                    
    evaluated = evaluate_sequences(beam)

    good = [
        v for v in evaluated
        if v["Score_TRSp"] >= threshold and v["Score_TRSpAvd"] >= threshold
    ]
    if good and N>=len(evaluated):
        best = max(good, key=lambda x: x["Score_geo_mean"])
        return [{
            "Original_Sequence": original_seq,
            "New_Variant": best["sequence"],
            "Score": best['Score_geo_mean'],
            "Rank":1,
            "Score_TRSp": best["Score_TRSp"],
            "Score_TRSpAvd": best["Score_TRSpAvd"]
        }]

    
    while beam and codon_changes_done <= CHANGES:
        codon_changes_done += 1
        variants = []
        for seq in beam:
            variants.extend(
                propose_single_codon_changes(
                    seq,dict_allowed_AAs,dict_allowed_AAs_max_min, frame_offset, freq_min,
                    forbidden_final, codon_usage
                )
            )

        variants = np.unique(variants)
        evaluated = evaluate_sequences(variants)
        good = [
            v for v in evaluated
            if v["Score_TRSp"] >= threshold and v["Score_TRSpAvd"] >= threshold
        ]
        if good:
            good.sort(key=lambda x: x["Score_geo_mean"], reverse=True)
            selected = good[:N]
        
            # 2) if fewer than N, fill with best overall
            if len(selected) < N:
                remaining = [
                    v for v in evaluated
                    if v["sequence"] not in {s["sequence"] for s in selected}
                ]
                remaining.sort(key=lambda x: x["Score_geo_mean"], reverse=True)
                selected.extend(remaining[: N - len(selected)])
        
            # 3) format output
            return [
                {
                    "Original_Sequence": original_seq,
                    "New_Variant": v["sequence"],
                    "Score": v["Score_geo_mean"],
                    "Rank": i+1,
                    "Score_TRSp": v["Score_TRSp"],
                    "Score_TRSpAvd": v["Score_TRSpAvd"],
                }
                for i,v in enumerate(selected)
            ]
        evaluated.sort(key=lambda x: x["Score_geo_mean"], reverse=True)
        # Keep only Pareto-optimal variants
        pareto_variants = pareto_front(evaluated)

        # Optional: still restrict beam size if too many
        pareto_variants.sort(key=lambda x: x["Score_geo_mean"], reverse=True)
        beam = [v["sequence"] for v in pareto_variants[:40]]
    selected=[]
    evaluated.sort(key=lambda x: x["Score_geo_mean"], reverse=True)

    remaining = [
                    v for v in evaluated
                    if v["sequence"] not in {s["sequence"] for s in selected}
                ]
    remaining.sort(key=lambda x: x["Score_geo_mean"], reverse=True)
    selected.extend(remaining[: N - len(selected)])
        
            # 3) format output
    return [
        {
            "Original_Sequence": original_seq,
            "New_Variant": v["sequence"],
            "Score": v["Score_geo_mean"],
            "Rank": i+1,
            "Score_TRSp": v["Score_TRSp"],
            "Score_TRSpAvd": v["Score_TRSpAvd"],
        }
        for i,v in enumerate(selected)
    ]

